import { useCallback, useEffect, useState } from 'react';
import { useIntl } from 'react-intl';

import {
  ChevronLeftSmallIcon,
  ChevronRightSmallIcon,
} from '@dynatrace/strato-icons';

import { StepperButtonTooltip } from './StepperButtonTooltip.js';
import { Button } from '../../../../buttons/button/Button.js';
import { isFullTimeframe } from '../../../../core/time/helpers.js';
import { useTimeframeSelectorStore } from '../../../../core/time/timeframeStore/useTimeframeStore.js';
import type { FormControlBaseProps } from '../../../../core/types/form-control-props.js';
import { Timeframe } from '../../../../core/types/time.js';
import { useTimeframeSelectorContext } from '../../hooks/useTimeframeSelectorContext.js';
import {
  formatStepperValues,
  getTimeShift,
} from '../../utils/stepper-helpers.js';
import {
  dateIsMinMax,
  isBiggerThan,
  isSmallerThan,
} from '../../utils/timeframe-selection.js';

//#region Typings
interface TimeframeStepperProps
  extends FormControlBaseProps<
    (timeframe: Timeframe, isMinOrMax: boolean) => void
  > {
  /** The direction the timeframe will be shifted to. */
  direction: 'backward' | 'forward';
  /**  Callback function to handle on blur events. */
  onBlur?: () => void;
}
//#endregion

function isStepperDisabled(
  direction: TimeframeStepperProps['direction'],
  value: Timeframe | null,
  min?: string,
  max?: string,
): boolean {
  if (!value) {
    return false;
  }

  if (direction === 'backward') {
    const nextStepIsValid =
      isSmallerThan(value.from.absoluteDate, min) ||
      dateIsMinMax(value.from, min);

    return nextStepIsValid;
  }

  if (direction === 'forward') {
    const nextStepIsValid =
      isBiggerThan(value.to.absoluteDate, max) ||
      dateIsMinMax(value.to, undefined, max);

    return nextStepIsValid;
  }

  return false;
}

/**
 * StepperButton component to shift the timeframe backward and forward.
 * @internal
 */
export const StepperButton = (props: TimeframeStepperProps) => {
  const {
    disabled,
    direction,
    'aria-disabled': ariaDisabledProp,
    onBlur,
    readOnly,
  }: TimeframeStepperProps = props;

  const { showError } = useTimeframeSelectorContext();
  const precision = useTimeframeSelectorStore((state) => state.precision);
  const min = useTimeframeSelectorStore((state) => state.min)?.value;
  const max = useTimeframeSelectorStore((state) => state.max)?.value;
  const isFullDay = useTimeframeSelectorStore((state) => state.isFullDay);
  const setTimeframeSelectorTimeframe = useTimeframeSelectorStore(
    (state) => state.setStepperValue,
  );
  const value = useTimeframeSelectorStore((state) =>
    isFullTimeframe(state.timeframeSelectorTimeframe)
      ? state.timeframeSelectorTimeframe
      : null,
  );
  const referenceTimeframe = useTimeframeSelectorStore(
    (state) => state.referenceTimeframe,
  );
  const setReferenceTimeframe = useTimeframeSelectorStore(
    (state) => state.setReferenceTimeframe,
  );

  const [shiftValue, setShiftValue] = useState<Timeframe | null>(value);

  const [isDisabled, setIsDisabled] = useState(
    isStepperDisabled(direction, value, min, max),
  );

  /** Handle value change. */
  useEffect(() => {
    setIsDisabled(isStepperDisabled(direction, value, min, max));

    const newShiftValue = getTimeShift(value, {
      direction,
      min,
      max,
      selectedOverCalendar: isFullDay,
      precision,
    });

    if (newShiftValue) {
      setShiftValue(newShiftValue);
    }
  }, [direction, value, min, max, isFullDay, isDisabled, precision]);

  /** Handle onClick. */
  const handleShift = useCallback(() => {
    // In case we have a referenceTimeframe, it means we are currently at a min or max value and want to restore
    // the previous timeframe when shifting back in the opposite direction. If there is no referenceTimeframe,
    // we just calculate the next step based on the current value as usual.
    const newShiftValue = getTimeShift(referenceTimeframe ?? value, {
      direction,
      min,
      max,
      selectedOverCalendar: isFullDay,
      precision,
    });

    if (newShiftValue && !readOnly) {
      const isAtMinOrMax =
        direction === 'backward'
          ? dateIsMinMax(newShiftValue?.from, min, max)
          : dateIsMinMax(newShiftValue?.to, min, max);

      if (referenceTimeframe && isFullTimeframe(referenceTimeframe)) {
        setTimeframeSelectorTimeframe(referenceTimeframe);
        setReferenceTimeframe(null);
        return;
      }

      if (isAtMinOrMax) {
        // In this case, moving to the minimum or maximum value means we can't maintain the original timeframe length.
        // Therefore, we store the previous timeframe so we can restore it when moving back in the opposite direction.
        setReferenceTimeframe(value);
      }
      setTimeframeSelectorTimeframe(newShiftValue);
    }
  }, [
    value,
    direction,
    min,
    max,
    isFullDay,
    precision,
    readOnly,
    referenceTimeframe,
    setReferenceTimeframe,
    setTimeframeSelectorTimeframe,
  ]);

  const intl = useIntl();

  const dataDtName = direction === 'backward' ? 'StepBackward' : 'StepForward';

  if (!value || !shiftValue) {
    return null;
  }

  const formattedStepperValue = formatStepperValues(
    shiftValue.from,
    shiftValue.to,
    intl,
    direction,
    isFullDay,
  );

  return (
    <StepperButtonTooltip
      disabled={disabled || isDisabled}
      value={shiftValue}
      formattedStepperValue={formattedStepperValue}
    >
      <Button
        style={{ minWidth: 'fit-content' }}
        variant="emphasized"
        color={showError ? 'critical' : 'neutral'}
        disabled={disabled || isDisabled}
        onClick={handleShift}
        aria-disabled={ariaDisabledProp}
        aria-label={formattedStepperValue}
        onBlur={onBlur}
        data-dt-name={dataDtName}
      >
        {direction === 'backward' ? (
          <ChevronLeftSmallIcon />
        ) : (
          <ChevronRightSmallIcon />
        )}
      </Button>
    </StepperButtonTooltip>
  );
};

(StepperButton as typeof StepperButton & { displayName: string }).displayName =
  'TimeframeStepperButton';
